@startuml
skinparam UMLClass fontname "Helvetica"
skinparam UMLActor fontname "Helvetica"
skinparam UMLInterface fontname "Helvetica"
skinparam UMLPackage fontname "Helvetica"

package "Dummy" as Dummy {
    private
    protected
    pkg method()
    public()
}

package "I" as Interface {
    firstName
    lastName
    dateOfBirth
    address
    email
}

package "C" as Class {
    createService()
    removeAccount()
    removeAccount()
    setHourlyRate()
    setForm(Service.type, customerInfo)
}

package "I" as Interface {
    createAccount(AccountType)
    login()
    logout()
}

package "C" as Class {
    createAccount(Employee)
    selectService()
    setBusinessHour()
    boolean processServiceRequest()
    notifyCustomer()
}

package "C" as Class {
    createAccount(Customer)
    searchBranch()
    selectService()
    getForm(Service.type).fill()
    submitForm()
    rateBranch()
}

package "I" as Interface {
    pickupTime
    returnTime
    licenseType
}

package "A" as Actor {
    pickupTime
    returnTime
    licenseType
}

package "C" as Class {
    carType
}

package "C" as Class {
    usageArea
}

package "I" as Interface {
    startLocation
    endLocation
    numberOfMovers
    numberOfBoxes
}

package "C" as Class {
    startLocation
    endLocation
    numberOfMovers
    numberOfBoxes
}

Class --> Interface : <<inherit>>
Class --> Interface : <<inherit>>
Class --> Interface : <<inherit>>

Interface --> Class : <<extend>>
Interface --> Class : <<extend>>
Interface --> Class : <<extend>>

Actor --> Interface : <<extend>>
Actor --> Class : <<extend>>
Actor --> Class : <<extend>>

Class --> Class : <<extend>>
Class --> Class : <<extend>>
Class --> Class : <<extend>>

Class --> Class : <<extend>>
Class --> Class : <<extend>>
Class --> Class : <<extend>>

@enduml
